@@ -2738,6 +2738,9 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
     if (std::optional<bool> KnownSignBit = computeKnownFPSignBit(
             Sign, /*Depth=*/0, getSimplifyQuery().getWithInstruction(II))) {
       if (*KnownSignBit) {
+      // Don't optimize if Mag could be NaN, as the sign bit of NaN matters
+      if (!isKnownNeverNaN(Mag, /*Depth=*/0, getSimplifyQuery().getWithInstruction(II)))
+        break;
         // If we know that the sign argument is negative, reduce to FNABS:
         // copysign Mag, -Sign --> fneg (fabs Mag)
         Value *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, Mag, II);
@@ -2745,6 +2748,9 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       }

       // If we know that the sign argument is positive, reduce to FABS:
+      // Don't optimize if Mag could be NaN, as the sign bit of NaN matters
+      if (!isKnownNeverNaN(Mag, /*Depth=*/0, getSimplifyQuery().getWithInstruction(II)))
+        break;
       // copysign Mag, +Sign --> fabs Mag
       Value *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, Mag, II);
       return replaceInstUsesWith(*II, Fabs);
